+fn truncate_utf8(s: &str, max_chars: usize) -> String {
+    if max_chars == 0 {
+        return s.to_string();
+    }
+
+    if max_chars == 1 {
+        return "…".to_string();
+    }
+
+    let cut = max_chars - 1;
+    for (count, (idx, _)) in s.char_indices().enumerate() {
+        if count == cut {
+            return format!("{}…", &s[..idx]);
+        }
+    }
+
+    s.to_string()
+}
+
+fn redact_quoted_strings(s: &str) -> String {
+    let mut out = String::with_capacity(s.len());
+    let mut it = s.chars();
+
+    while let Some(c) = it.next() {
+        match c {
+            '\'' => {
+                out.push('\'');
+                out.push('…');
+                for next in it.by_ref() {
+                    if next == '\'' {
+                        out.push('\'');
+                        break;
+                    }
+                }
+            }
+            '"' => {
+                out.push('"');
+                out.push('…');
+                let mut escaped = false;
+                for next in it.by_ref() {
+                    if escaped {
+                        escaped = false;
+                        continue;
+                    }
+                    if next == '\\' {
+                        escaped = true;
+                        continue;
+                    }
+                    if next == '"' {
+                        out.push('"');
+                        break;
+                    }
+                }
+            }
+            _ => out.push(c),
+        }
+    }
+
+    out
+}
+
+fn redact_aggressively(s: &str) -> String {
+    // First pass: redact quoted strings (most likely secret-bearing spans).
+    let s = redact_quoted_strings(s);
+
+    // Second pass: redact KEY=VALUE tokens when key looks secret-y.
+    // This keeps output debuggable while avoiding accidental leakage.
+    let mut out = String::with_capacity(s.len());
+    let mut token = String::new();
+
+    for c in s.chars() {
+        if c.is_whitespace() {
+            if !token.is_empty() {
+                out.push_str(&redact_token(&token));
+                token.clear();
+            }
+            out.push(c);
+        } else {
+            token.push(c);
+        }
+    }
+
+    if !token.is_empty() {
+        out.push_str(&redact_token(&token));
+    }
+
+    out
+}
+
+fn redact_token(token: &str) -> String {
+    // Redact long hex-ish blobs (common for hashes/keys).
+    if token.len() >= 32 && token.chars().all(|c| c.is_ascii_hexdigit()) {
+        return "…".to_string();
+    }
+
+    if let Some(eq) = token.find('=') {
+        let lower = token[..eq].to_ascii_lowercase();
+        let (k, _v) = token.split_at(eq + 1);
+        if lower.contains("token")
+            || lower.contains("secret")
+            || lower.contains("password")
+            || lower.contains("passwd")
+            || lower.contains("api_key")
+            || lower.contains("apikey")
+            || lower.contains("bearer")
+        {
+            return format!("{k}…");
+        }
+    }
+
+    token.to_string()
 }

